const menuToggle=document.getElementById("menuToggle");const nav=document.getElementById("nav");const themeToggle=document.getElementById("themeToggle");const topButton=document.getElementById("topButton");const year=document.getElementById("year");if(year){year.textContent=new Date().getFullYear();}const themeKey="adioranye-tech-portfolio-theme";const savedTheme=localStorage.getItem(themeKey);const prefersLight=window.matchMedia && window.matchMedia("(prefers-color-scheme:light)").matches;if(savedTheme==="light" ||(!savedTheme && prefersLight)){document.body.classList.add("light");if(themeToggle)themeToggle.textContent="☾";}if(menuToggle && nav){menuToggle.addEventListener("click",()=>{const isOpen=nav.classList.toggle("open");menuToggle.setAttribute("aria-expanded",String(isOpen));});nav.querySelectorAll("a").forEach((link)=>{link.addEventListener("click",()=>{nav.classList.remove("open");menuToggle.setAttribute("aria-expanded","false");});});}if(themeToggle){themeToggle.addEventListener("click",()=>{const isLight=document.body.classList.toggle("light");themeToggle.textContent=isLight?"☾":"◐";localStorage.setItem(themeKey,isLight?"light":"dark");});}if(topButton){window.addEventListener("scroll",()=>{topButton.classList.toggle("show",window.scrollY>620);},{passive:true});topButton.addEventListener("click",()=>{window.scrollTo({top:0,behavior:"smooth"});});}const revealItems=document.querySelectorAll(".reveal");if("IntersectionObserver" in window){const observer=new IntersectionObserver((entries)=>{entries.forEach((entry)=>{if(entry.isIntersecting){entry.target.classList.add("visible");observer.unobserve(entry.target);}});},{threshold:0.12,rootMargin:"0px 0px-40px 0px"});revealItems.forEach((item)=>observer.observe(item));}else{revealItems.forEach((item)=>item.classList.add("visible"));}